import {useMemo} from 'react';
import {useKitsTheme} from '../Contexts/Theme';

export interface UseComponentDefaultsResult<T> {
    /** Props with theme defaults merged in (user props always win) */
    mergedProps: T;
    /** CSS style overrides from theme.components[name].style */
    themeStyle: Record<string, any>;
}

/**
 * Merges theme-level component defaults with user-supplied props.
 * Returns both merged props and theme style overrides.
 *
 * @example
 * function Button(rawProps: IButtonProps) {
 *   const { mergedProps: props, themeStyle } = useComponentDefaults('Button', rawProps);
 *   // props now includes theme.components.Button.props defaults
 *   // themeStyle contains theme.components.Button.style overrides
 * }
 */
export default function useComponentDefaults<T extends Record<string, any>>(
    componentName: string,
    props: T,
): UseComponentDefaultsResult<T> {
    const {theme} = useKitsTheme();
    const config = theme.components[componentName];

    return useMemo(() => {
        if (!config) return {mergedProps: props, themeStyle: {}};

        // Merge prop defaults under user props (user always wins)
        const defaults = config.props || {};
        const merged = {...defaults} as Record<string, any>;
        for (const key of Object.keys(props)) {
            if (props[key] !== undefined) {
                merged[key] = props[key];
            }
        }

        return {
            mergedProps: merged as T,
            themeStyle: config.style || {},
        };
    }, [config, props]);
}
